from pyxrd.generic.controllers.dialog_controller import DialogController
from pyxrd.refinement.parspace import ParameterSpaceGenerator

class RefinerController(DialogController):
    """
        A controller for a Refiner object that keeps track
        of the solutions and residuals generated by the refinement
        algorithm.
    """

    auto_adapt_excluded = [
        "refine_method_index",
        "refinables",
        "make_psp_plots",
    ]

    register_lazy = False
    _plot_png = None

    def __init__(self, refiner, *args, **kwargs):
        super(RefinerController, self).__init__(*args, **kwargs)
        self.refiner = refiner

    # ------------------------------------------------------------
    #      GTK Signal handlers
    # ------------------------------------------------------------
    def on_cancel(self):
        self.view.hide()
        self.parent.parent.view.parent.show()

    def on_btn_initial_clicked(self, event):
        self.refiner.apply_initial_solution()
        del self.refiner
        self.on_cancel()
        return True

    def on_btn_best_clicked(self, event):
        self.refiner.apply_best_solution()
        del self.refiner
        self.on_cancel()
        return True

    def on_btn_last_clicked(self, event):
        self.refiner.apply_last_solution()
        del self.refiner
        self.on_cancel()
        return True

    def on_btn_show_plot_clicked(self, event):
        if self._plot_png is not None:
            self.view.show_plot_popup(self._plot_png)
        return True

    # ------------------------------------------------------------
    #      Methods & Functions
    # ------------------------------------------------------------
    def _get_avg_gof(self):
        """
        Compute average GoF across all specimens using the current calculated
        pattern (call after apply_best/last/initial_solution).
        num_params = number of refined parameters for degrees-of-freedom correction.
        """
        num_params = len(self.refiner.refinables)
        values = [
            s.statistics.compute_gof(num_params)
            for s in self.model.mixture.specimens
            if s is not None
        ]
        return sum(values) / len(values) if values else 0.0

    def update_labels(self, elapsed=None):
        self.view.update_labels(
            self.refiner.history.initial_residual,
            self.refiner.history.best_residual,
            self.refiner.history.last_residual,
            gof=self._get_avg_gof(),
            elapsed=elapsed,
        )

    def generate_images(self, density=200):
        import io
        samples = self.refiner.get_plot_samples()
        labels = self.refiner.get_plot_labels()
        truths = self.refiner.history.best_solution

        psg = ParameterSpaceGenerator()
        psg.initialize(self.refiner.ranges, 199)
        for sample in samples:
            psg.record(sample[:-1], sample[-1])
        psg.plot_images(self.view.figure, truths, labels[:-1])

        buf = io.BytesIO()
        self.view.figure.savefig(buf, format='png', dpi=100, bbox_inches='tight')
        self._plot_png = buf.getvalue()
        self.view["btn_show_plot"].set_sensitive(True)

    def populate_log(self, elapsed=None):
        refiner = self.refiner
        sep = "=" * 58
        lines = [sep, "  Refinement Summary", sep, ""]

        lines.append("  Method:       %s" % refiner.method)
        lines.append("  Parameters:   %d" % len(refiner.refinables))
        if elapsed is not None:
            mins, secs = divmod(int(elapsed), 60)
            lines.append("  Time elapsed: %d:%02d" % (mins, secs))
        lines.append("")

        # Parameter table
        lines.append("  Parameters:")
        lines.append("  %-30s %12s %12s" % ("Name", "Initial", "Best"))
        lines.append("  " + "-" * 56)
        initial = refiner.history.initial_solution
        best = refiner.history.best_solution
        for i, ref_prop in enumerate(refiner.refinables):
            lines.append("  %-30s %12.6f %12.6f" % (
                ref_prop.text_descriptor, initial[i], best[i]
            ))
        lines.append("")

        # Residuals
        lines.append("  Residuals:")
        lines.append("    Initial : %.6f" % refiner.history.initial_residual)
        lines.append("    Best    : %.6f" % refiner.history.best_residual)
        lines.append("    Last    : %.6f" % refiner.history.last_residual)
        lines.append("    GoF     : %.4f  (best solution, P=%d)" % (
            self._get_avg_gof(), len(refiner.refinables)))
        lines.append("")

        # Iteration log
        iter_data = refiner.history.get_residual_per_iteration()
        if iter_data:
            lines.append("  Iteration log:")
            lines.append("  %8s  %14s" % ("Iter", "Residual"))
            lines.append("  " + "-" * 24)
            for entry in iter_data:
                iteration, residual = int(entry[0]), float(entry[1])
                lines.append("  %8d  %14.6f" % (iteration, residual))
            lines.append("")

        lines.append(sep)
        self.view.set_log_text("\n".join(lines))

    pass # end of class
